#!/usr/bin/env node
// Reads every registry/<id>/ folder (via scripts/lib/read-registry.mjs) and
// emits the typed src/registry.data.ts that the runtime imports. Deterministic:
// entries are sorted by template_id so the generated file is stable across runs.

import { writeFileSync } from "node:fs";
import { join } from "node:path";
import { readAllEntries, rootDir, toBundleEntry } from "./lib/read-registry.mjs";

const outFile = join(rootDir, "src", "registry.data.ts");

function main() {
  const entries = readAllEntries().map(toBundleEntry);
  const banner =
    "// AUTO-GENERATED by scripts/build-registry.mjs. Do not edit by hand.\n" +
    "// Run `npm run build:registry` after changing anything under registry/.\n";
  const body =
    'import type { RegistryEntry } from "./registry-types.js";\n\n' +
    `export const REGISTRY_DATA: RegistryEntry[] = ${JSON.stringify(entries, null, 2)};\n`;

  writeFileSync(outFile, `${banner}\n${body}`, "utf8");
  console.error(
    `build-registry: wrote ${entries.length} component(s) to src/registry.data.ts`,
  );
}

main();
